# calibrate_judge.py
def calibration_report(human_results: list[dict], judge_results: list[dict]) -> dict:
    per_criterion: dict[str, dict] = {}
    for human, judge in zip(human_results, judge_results):
        for cid, h_result in human["criteria_results"].items():
            j_result = judge["criteria_results"].get(cid)
            if j_result is None:
                continue
            per_criterion.setdefault(cid, {"agree": 0, "total": 0})
            per_criterion[cid]["total"] += 1
            if h_result["verdict"] == j_result["verdict"]:
                per_criterion[cid]["agree"] += 1

    report = {}
    for cid, counts in per_criterion.items():
        agreement = counts["agree"] / counts["total"]
        report[cid] = {
            "agreement": round(agreement, 3),
            "calibrated": agreement >= 0.85,
        }
    return report

# uat_report.py — aggregate UAT results into a release recommendation
from dataclasses import dataclass, field

@dataclass
class UATSummary:
    feature: str
    release: str
    total_scenarios: int
    blocking_failures: list[str] = field(default_factory=list)
    category_scores: dict[str, float] = field(default_factory=dict)
    human_scores: dict[str, float] = field(default_factory=dict)

    @property
    def recommendation(self) -> str:
        if self.blocking_failures:
            return "HOLD"
        if any(s < 0.80 for s in self.category_scores.values()):
            return "CONDITIONAL"
        if any(s < 4.0 for s in self.human_scores.values()):
            return "CONDITIONAL"
        return "SHIP"

    def to_markdown(self) -> str:
        lines = [
            f"# UAT Report: {self.feature} ({self.release})",
            f"**Recommendation: {self.recommendation}**",
            f"Scenarios evaluated: {self.total_scenarios}",
            "",
            "## Category Scores (automated)",
        ]
        for cat, score in self.category_scores.items():
            status = "✓" if score >= 0.80 else "✗"
            lines.append(f"- {status} {cat}: {score:.0%}")
        lines += ["", "## Human Tester Scores"]
        for dim, score in self.human_scores.items():
            status = "✓" if score >= 4.0 else "✗"
            lines.append(f"- {status} {dim}: {score:.1f}/5.0")
        if self.blocking_failures:
            lines += ["", "## Blocking Failures (must fix before release)"]
            for f in self.blocking_failures:
                lines.append(f"- {f}")
        return "\n".join(lines)
